var Container = require('../../../com/container/container');
var context = require('../context');

var UnReadMsg = function(){};

Container._extend(UnReadMsg, {
  _className: 'unreadmsg',
  __filename: __filename,
  initData: function(){
    this.data = {
      url: context.urls
    };
  },
  initEvents: function(){
    UnReadMsg.prototype._super.initEvents.call(this);
  },
  afterComplete : function(){
    UnReadMsg.prototype._super.afterComplete.call(this);
    var table = this.query("*[name=unreadSelectTab]");
    table.store.loadPage(1, {});
  }
});

exports = module.exports = UnReadMsg;
